css:
body {
            font-family: Arial, sans-serif;
            font-size: 10pt;
            margin: 0;
            padding: 20px;
        }

        .quotation-header {
            text-align: center;
            border: 2px solid black;
            margin-bottom: 0;
        }

        .company-name {
            font-size: 16pt;
            font-weight: bold;
            margin-bottom: 5px;
        }

        .company-address {
            font-size: 9pt;
            line-height: 1.2;
        }

        .quotation-title {
            font-size: 12pt;
            font-weight: bold;
            /* margin-top: 5px; */
        }

        .quote-info-table {
            width: 100%;
            border-collapse: collapse;
            border: 2px solid black;
            border-top: none;
            margin-bottom: 0;
        }

        .quote-info-table td {
            border: 1px solid black;
            padding: 5px;
            font-size: 9pt;
        }

        .quote-info-left {
            width: 50%;
            vertical-align: top;
        }

        .quote-info-right {
            width: 50%;
            vertical-align: top;
        }

        .party-details-table {
            width: 100%;
            border-collapse: collapse;
            border: 2px solid black;
            border-top: none;
        }

        .party-details-table td {
            border: 1px solid black;
            padding: 8px;
            font-size: 9pt;
            vertical-align: top;
        }

        .party-header {
            font-weight: bold;
            background-color: #f5f5f5;
        }

        .items-table {
            width: 100%;
            border-collapse: collapse;
            border: 2px solid black;
            border-top: none;
            margin-bottom: 0;
        }

        .items-table th,
        .items-table td {
            border: 1px solid black;
            padding: 4px;
            font-size: 8pt;
            text-align: center;
        }

        .items-table th {
            background-color: #f5f5f5;
            font-weight: bold;
        }

        .items-table .description {
            text-align: left;
            width: 200px;
        }

        .total-row {
            font-weight: bold;
        }

        .footer-table {
            width: 100%;
            border-collapse: collapse;
            border: 2px solid black;
            border-top: none;
        }

        .footer-table td {
            border: 0px solid black;
            padding: 8px;
            font-size: 9pt;
            vertical-align: top;
        }

        .amount-words {
            font-style: italic;
        }

        .signature-section {
            text-align: right;
            margin-top: 20px;
        }

        @media print {
            body { margin: 0; }
            .page-break { page-break-before: always; }
        }

        .print-format td, .print-format th {
            padding: 5px !important;
        }

        .items-table th, .items-table td {
            border: 0px solid black;
            padding: 4px;
            font-size: 7pt;
            text-align: center;
            border-left: 1px solid black;
            border-right: 1px solid black
        }
